#include <stdio.h>
#include <stdlib.h>
#define MAX_SIZE 100

typedef struct Queue {
    int items[MAX_SIZE];
    int front_idx;
    int rear;
} Queue;

void initQueue(Queue* queue) {
    queue->front_idx = 0;
    queue->rear = -1;
}

void enqueue(Queue* queue, int item) {
    if (queue->rear < MAX_SIZE - 1) {
        queue->items[++queue->rear] = item;
    }
}

int dequeue(Queue* queue) {
    if (!isEmpty(queue)) {
        return queue->items[queue->front_idx++];
    }
    return -1;
}

int front(Queue* queue) {
    if (!isEmpty(queue)) {
        return queue->items[queue->front_idx];
    }
    return -1;
}

int isEmpty(Queue* queue) {
    return queue->front_idx > queue->rear;
}

void printQueue(Queue* queue) {
    printf("[");
    for (int i = queue->front_idx; i <= queue->rear; i++) {
        printf("%d", queue->items[i]);
        if (i < queue->rear) printf(", ");
    }
    printf("]\n");
}

int main() {
    Queue queue;
    initQueue(&queue);
    int values[] = {5, 10, 15};
    for (int i = 0; i < 3; i++) {
        enqueue(&queue, values[i]);
    }
    printf("Queue after enqueue: ");
    printQueue(&queue);
    int dequeued = dequeue(&queue);
    printf("Dequeued item: %d\n", dequeued);
    printf("Queue after dequeue: ");
    printQueue(&queue);
    printf("Front item: %d\n", front(&queue));
    return 0;
}
// Output: Queue after enqueue: [5, 10, 15]
// Output: Dequeued item: 5
// Output: Queue after dequeue: [10, 15]
// Output: Front item: 10

