#include <iostream>
#include <vector>

class Queue {
private:
    std::vector<int> items;

public:
    void enqueue(int item) {
        items.push_back(item);
    }

    int dequeue() {
        if (!isEmpty()) {
            int item = items.front();
            items.erase(items.begin());
            return item;
        }
        return -1;
    }

    int front() {
        if (!isEmpty()) {
            return items.front();
        }
        return -1;
    }

    bool isEmpty() {
        return items.empty();
    }

    std::vector<int> toVector() {
        return items;
    }
};

int main() {
    Queue queue;
    int values[] = {5, 10, 15};
    for (int val : values) {
        queue.enqueue(val);
    }
    std::cout << "Queue after enqueue: [";
    auto result = queue.toVector();
    for (size_t i = 0; i < result.size(); i++) {
        std::cout << result[i];
        if (i < result.size() - 1) std::cout << ", ";
    }
    std::cout << "]\n";
    int dequeued = queue.dequeue();
    std::cout << "Dequeued item: " << dequeued << "\n";
    std::cout << "Queue after dequeue: [";
    result = queue.toVector();
    for (size_t i = 0; i < result.size(); i++) {
        std::cout << result[i];
        if (i < result.size() - 1) std::cout << ", ";
    }
    std::cout << "]\n";
    std::cout << "Front item: " << queue.front() << "\n";
    return 0;
}
// Output: Queue after enqueue: [5, 10, 15]
